<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
body{font-family:'Segoe UI',Tahoma,Geneva,Verdana,sans-serif;background:#f0f2f5;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:20px;color:#1a1a2e}
.container{background:#fff;border-radius:12px;box-shadow:0 4px 24px rgba(0,0,0,.08);width:100%;max-width:520px;padding:40px 36px}
.header{text-align:center;margin-bottom:32px}
.header h1{font-size:1.6rem;font-weight:700;color:#1a3a5c;margin-bottom:8px;letter-spacing:-.3px}
.header p{font-size:.92rem;color:#6b7a8d;line-height:1.5}
.form-group{margin-bottom:22px}
.form-group label{display:block;font-size:.85rem;font-weight:600;color:#2c3e50;margin-bottom:8px}
.form-group label .required{color:#e74c3c;margin-left:2px}
.file-upload-wrapper{position:relative}
.file-upload-wrapper input[type="file"]{display:none}
.file-upload-btn{display:flex;align-items:center;justify-content:center;gap:10px;width:100%;padding:18px 16px;border:2px dashed #b0c4d8;border-radius:8px;background:#f8fafc;color:#4a6fa5;font-size:.9rem;font-weight:500;cursor:pointer;transition:all .2s ease}
.file-upload-btn:hover{border-color:#2e6da4;background:#eef3f9}
.file-upload-btn svg{width:22px;height:22px;flex-shrink:0}
.file-upload-btn .file-name{font-weight:600;color:#1a3a5c;text-align:center;word-break:break-all}
.file-upload-btn.has-file{border-color:#27ae60;border-style:solid;background:#f0faf4;color:#1e8449}
.file-upload-btn.has-file svg{color:#27ae60}
.file-size-error{font-size:.8rem;color:#e74c3c;margin-top:6px;display:none}
.date-input{width:100%;padding:12px 14px;border:1.5px solid #cdd6e0;border-radius:8px;font-size:.9rem;color:#2c3e50;background:#f8fafc;transition:border-color .2s ease;font-family:inherit}
.date-input:focus{outline:none;border-color:#2e6da4;background:#fff}
