<body>
<div class="container">
  <div class="header">
    <h1>Relatório Financeiro PRN</h1>
    <p>Upload das planilhas para geração do relatório</p>
  </div>

  <form id="reportForm" method="POST" enctype="multipart/form-data" action="https://prndiag1.app.n8n.cloud/webhook/prn/report" novalidate>
    <div class="form-group">
      <label>Planilha Diária <span class="required">*</span></label>
      <div class="file-upload-wrapper">
        <div class="file-upload-btn" id="dailyDropZone" tabindex="0" role="button" aria-label="Selecionar Planilha Diária">
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"/></svg>
          <span id="dailyLabel">Clique ou arraste a planilha (.xlsx)</span>
        </div>
        <input type="file" id="dailyFile" name="daily_file" accept=".xlsx">
      </div>
      <div class="file-size-error" id="dailySizeError">O arquivo excede o limite de 10MB.</div>
    </div>

    <div class="form-group">
      <label>Planilha Histórica PRN <span class="required">*</span></label>
      <div class="file-upload-wrapper">
        <div class="file-upload-btn" id="historicalDropZone" tabindex="0" role="button" aria-label="Selecionar Planilha Histórica PRN">
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"/></svg>
          <span id="historicalLabel">Clique ou arraste a planilha (.xlsx)</span>
        </div>
        <input type="file" id="historicalFile" name="historical_file" accept=".xlsx">
      </div>
      <div class="file-size-error" id="historicalSizeError">O arquivo excede o limite de 10MB.</div>
    </div>

    <div class="form-group">
      <label for="referenceDate">Data de Referência <span style="color:#95a5b6;font-weight:400">(opcional)</span></label>
      <input type="date" id="referenceDate" name="reference_date" class="date-input">
    </div>

    <button type="submit" class="submit-btn" id="submitBtn">Gerar Relatório</button>
  </form>

  <div class="error-message" id="errorMessage">
    <div class="error-title">Erro ao processar</div>
    <div class="error-text" id="errorText"></div>
  </div>

  <div class="footer">Sistema de Relatórios Financeiros</div>
</div>

<script>
(function() {
  var MAX_SIZE = 10 * 1024 * 1024;
  var dailyFileInput = document.getElementById('dailyFile');
  var historicalFileInput = document.getElementById('historicalFile');
  var dailyDropZone = document.getElementById('dailyDropZone');
  var historicalDropZone = document.getElementById('historicalDropZone');
  var dailyLabel = document.getElementById('dailyLabel');
  var historicalLabel = document.getElementById('historicalLabel');
  var dailySizeError = document.getElementById('dailySizeError');
  var historicalSizeError = document.getElementById('historicalSizeError');
  var form = document.getElementById('reportForm');
  var submitBtn = document.getElementById('submitBtn');
  var errorMessage = document.getElementById('errorMessage');
  var errorText = document.getElementById('errorText');

  function handleFileSelect(input, dropZone, label, sizeError) {
    input.addEventListener('change', function() {
      sizeError.style.display = 'none';
      if (input.files && input.files.length > 0) {
        var file = input.files[0];
        if (file.size > MAX_SIZE) {
          input.value = '';
          label.textContent = 'Clique ou arraste a planilha (.xlsx)';
          dropZone.classList.remove('has-file');
          sizeError.style.display = 'block';
          return;
        }
        label.textContent = file.name;
        dropZone.classList.add('has-file');
      } else {
        label.textContent = 'Clique ou arraste a planilha (.xlsx)';
        dropZone.classList.remove('has-file');
      }
    });

    dropZone.addEventListener('click', function() { input.click(); });
    dropZone.addEventListener('keydown', function(e) {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); input.click(); }
    });

    dropZone.addEventListener('dragover', function(e) { e.preventDefault(); dropZone.style.borderColor = '#2e86c1'; });
    dropZone.addEventListener('dragleave', function(e) {
      e.preventDefault();
      dropZone.style.borderColor = dropZone.classList.contains('has-file') ? '#27ae60' : '#b0c4d8';
    });
    dropZone.addEventListener('drop', function(e) {
      e.preventDefault();
      dropZone.style.borderColor = '';
      var files = e.dataTransfer.files;
      if (files.length > 0) {
        input.files = files;
        input.dispatchEvent(new Event('change'));
      }
    });
  }

  handleFileSelect(dailyFileInput, dailyDropZone, dailyLabel, dailySizeError);
  handleFileSelect(historicalFileInput, historicalDropZone, historicalLabel, historicalSizeError);

  function showError(msg) {
    errorText.textContent = msg;
    errorMessage.style.display = 'block';
  }

  form.addEventListener('submit', function(e) {
    e.preventDefault();
    errorMessage.style.display = 'none';
    dailySizeError.style.display = 'none';
    historicalSizeError.style.display = 'none';

    if (!dailyFileInput.files || dailyFileInput.files.length === 0) {
      showError('Selecione a Planilha Diária para continuar.');
      return;
    }
    if (!historicalFileInput.files || historicalFileInput.files.length === 0) {
      showError('Selecione a Planilha Histórica PRN para continuar.');
      return;
    }
    if (dailyFileInput.files[0].size > MAX_SIZE) {
      dailySizeError.style.display = 'block';
      return;
    }
    if (historicalFileInput.files[0].size > MAX_SIZE) {
      historicalSizeError.style.display = 'block';
      return;
    }

    submitBtn.disabled = true;
    submitBtn.innerHTML = '<span class="spinner"></span>Processando...';

    form.submit();
  });
})();
</script>
</body>
</html>
