// ===== CALCULATOR =====
/**
 * calculator.js - Financial Calculation Engine for PRN Reporting
 *
 * Receives normalized data from normalizer.js and performs all financial
 * calculations needed for the n8n reporting workflow.
 *
 * Input: normalizedData object (see normalizer.js output schema)
 * Output: { summary, topDespesas, despesasPorCategoria, recebidosPorConta, historyAnalysis, warnings }
 */

// --- Helpers ---

/**
 * Rounds a numeric value to 2 decimal places.
 * Uses a multiplier trick to avoid floating-point precision issues.
 * @param {number} value
 * @returns {number}
 */
function round2(value) {
  if (typeof value !== 'number' || isNaN(value)) return 0;
  return Math.round((value + Number.EPSILON) * 100) / 100;
}

/**
 * Safely reads a numeric property, defaulting to 0 if missing or non-numeric.
 * @param {object} obj
 * @param {string} prop
 * @returns {number}
 */
function numProp(obj, prop) {
  const raw = obj[prop];
  if (typeof raw === 'number' && !isNaN(raw)) return raw;
  if (typeof raw === 'string') {
    const parsed = parseFloat(raw.replace(/[^\d.,-]/g, '').replace(',', '.'));
    return isNaN(parsed) ? 0 : parsed;
  }
  return 0;
}

/**
 * Groups an array of objects by a given key, then reduces with a custom
 * accumulator function to produce { [key]: accumulated }.
 *
 * @param {Array} items       - Array of row objects.
 * @param {string} groupKey   - Property name to group by.
 * @param {string} sumKey     - Property name whose numeric values are summed.
 * @returns {Object}          - { groupValue: { total, count } }
 */
function groupAndSum(items, groupKey, sumKey) {
  const groups = {};

  for (const item of items) {
    const key = String(item[groupKey] || 'Indefinido').trim();
    const value = round2(numProp(item, sumKey));

    if (!groups[key]) {
      groups[key] = { total: 0, count: 0 };
    }
    groups[key].total = round2(groups[key].total + value);
    groups[key].count += 1;
  }

  return groups;
}

/**
 * Converts a grouped result object into a sorted array.
 *
 * @param {Object}  groups  - Output of groupAndSum().
 * @param {boolean} desc    - Sort descending when true.
 * @returns {Array<{ key: string, total: number, count: number }>}
 */
function groupedToSortedArray(groups, desc = true) {
  return Object.entries(groups)
    .map(([key, data]) => ({ key, ...data }))
    .sort((a, b) => (desc ? b.total - a.total : a.total - b.total));
}

// --- Main entry point ---

/**
 * Performs all financial calculations on normalized PRN data.
 *
 * @param {object} normalizedData  - The full normalized payload from normalizer.js.
 * @returns {{ summary, topDespesas, despesasPorCategoria, recebidosPorConta, historyAnalysis, warnings }}
 */
function calculateFinancials(normalizedData) {
  const warnings = [];

  // ------------------------------------------------------------------
  // 1. Defensive defaults – ensure every expected section exists
  // ------------------------------------------------------------------
  const entities  = Array.isArray(normalizedData.entities)  ? normalizedData.entities  : [];
  const expenses  = Array.isArray(normalizedData.expenses)  ? normalizedData.expenses  : [];
  const receipts  = Array.isArray(normalizedData.receipts)  ? normalizedData.receipts  : [];
  const balances  = Array.isArray(normalizedData.balances)  ? normalizedData.balances  : [];
  const history   = normalizedData.history || {};
  const historyRows   = Array.isArray(history.rows)          ? history.rows      : [];
  const historySummary = history.summary || {};

  // ------------------------------------------------------------------
  // 2. Summary calculations
  // ------------------------------------------------------------------

  // Sum all expense valores across every entity
  const totalDespesas = round2(
    expenses.reduce((acc, e) => acc + numProp(e, 'valor'), 0)
  );

  // Sum all receipt valores across every entity
  const totalRecebido = round2(
    receipts.reduce((acc, r) => acc + numProp(r, 'valor'), 0)
  );

  // Aggregate bank and investment balances from entity metadata
  const saldoBancario = round2(
    entities.reduce((acc, e) => acc + numProp(e, 'saldoBancario'), 0)
  );
  const saldoAplicacoes = round2(
    entities.reduce((acc, e) => acc + numProp(e, 'saldoAplicacoes'), 0)
  );

  // Placeholder – future versions will compute the required transfer amount
  const transferenciaNecessaria = 0;

  const summary = {
    totalDespesas,
    totalRecebido,
    saldoBancario,
    saldoAplicacoes,
    transferenciaNecessaria,
  };

  // ------------------------------------------------------------------
  // 3. Top 10 despesas by valor (descending)
  // ------------------------------------------------------------------
  const topDespesas = [...expenses]
    .sort((a, b) => numProp(b, 'valor') - numProp(a, 'valor'))
    .slice(0, 10)
    .map(e => ({
      favorecido: e.favorecido || '',
      categoria:  e.categoria  || '',
      valor:      round2(numProp(e, 'valor')),
      vencimento: e.vencimento || '',
      entity:     e.entity     || '',
    }));

  // ------------------------------------------------------------------
  // 4. Despesas grouped by categoria
  // ------------------------------------------------------------------
  const despesasPorCategoria = groupedToSortedArray(
    groupAndSum(expenses, 'categoria', 'valor')
  ).map(({ key, total, count }) => ({
    categoria: key,
    total,
    count,
  }));

  // ------------------------------------------------------------------
  // 5. Recebidos grouped by contaCorrente
  // ------------------------------------------------------------------
  const recebidosPorConta = groupedToSortedArray(
    groupAndSum(receipts, 'contaCorrente', 'valor')
  ).map(({ key, total, count }) => ({
    contaCorrente: key,
    total,
    count,
  }));

  // ------------------------------------------------------------------
  // 6. History analysis
  // ------------------------------------------------------------------

  // Pass-through scalar fields from the history summary
  const totalRecords = historySummary.totalRecords || 0;
  const periodStart  = historySummary.periodStart  || '';
  const periodEnd    = historySummary.periodEnd    || '';

  // totalPago – sum valorLiquido where situacao === "pago"
  const totalPago = round2(
    historyRows
      .filter(r => (r.situacao || '').toLowerCase() === 'pago')
      .reduce((acc, r) => acc + numProp(r, 'valorLiquido'), 0)
  );

  // totalAtrasado – sum valorLiquido where situacao === "atrasado"
  const totalAtrasado = round2(
    historyRows
      .filter(r => (r.situacao || '').toLowerCase() === 'atrasado')
      .reduce((acc, r) => acc + numProp(r, 'valorLiquido'), 0)
  );

  // topCategorias – group history rows by categoria, sum valorLiquido, top 10
  const historyCatGroups = groupAndSum(historyRows, 'categoria', 'valorLiquido');
  const topCategorias = groupedToSortedArray(historyCatGroups)
    .slice(0, 10)
    .map(({ key, total }) => ({ categoria: key, total }));

  // topFornecedores – group history rows by fornecedor, sum valorLiquido, top 10
  const historyForGroups = groupAndSum(historyRows, 'fornecedor', 'valorLiquido');
  const topFornecedores = groupedToSortedArray(historyForGroups)
    .slice(0, 10)
    .map(({ key, total }) => ({ fornecedor: key, total }));

  // distribuicaoContas – group history rows by contaCorrente, sum valorLiquido
  const historyContaGroups = groupAndSum(historyRows, 'contaCorrente', 'valorLiquido');
  const distribuicaoContas = groupedToSortedArray(historyContaGroups, false)
    .map(({ key, total }) => ({ conta: key, total }));

  const historyAnalysis = {
    totalRecords,
    periodStart,
    periodEnd,
    totalPago,
    totalAtrasado,
    topCategorias,
    topFornecedores,
    distribuicaoContas,
  };

  // ------------------------------------------------------------------
  // 7. Warnings / alerts
  // ------------------------------------------------------------------

  // Warn if totalRecebido is more than 30% below totalDespesas
  if (totalDespesas > 0) {
    const ratio = totalRecebido / totalDespesas;
    if (ratio < 0.70) {
      const deficitPercent = round2((1 - ratio) * 100);
      warnings.push(
        `Receita significativamente inferior a despesas (${deficitPercent}% abaixo). ` +
        `Recebido: R$ ${totalRecebido.toFixed(2)} | Despesas: R$ ${totalDespesas.toFixed(2)}`
      );
    }
  }

  // Warn if aggregate saldoBancario is negative
  if (saldoBancario < 0) {
    warnings.push(
      `Saldo bancario total negativo: R$ ${saldoBancario.toFixed(2)}`
    );
  }

  // Warn for each entity with a negative saldoBancario
  for (const entity of entities) {
    const entitySaldo = numProp(entity, 'saldoBancario');
    if (entitySaldo < 0) {
      warnings.push(
        `Entidade "${entity.label || entity.code}" com saldo bancario negativo: R$ ${entitySaldo.toFixed(2)}`
      );
    }
  }

  // Carry forward any warnings that arrived with the input (idempotent merge)
  if (Array.isArray(normalizedData.warnings)) {
    for (const w of normalizedData.warnings) {
      if (typeof w === 'string' && w.length > 0 && !warnings.includes(w)) {
        warnings.push(w);
      }
    }
  }

  // ------------------------------------------------------------------
  // 8. Return the complete result
  // ------------------------------------------------------------------
  return {
    summary,
    topDespesas,
    despesasPorCategoria,
    recebidosPorConta,
    historyAnalysis,
    warnings,
  };
}

